/**
 * Cross-language serialization verification tests.
 *
 * Reads JSON fixture files generated by the Rust `generate_json_fixtures` test
 * (or hand-crafted equivalents) and verifies that each fixture has the expected
 * shape and round-trips correctly through JSON.parse / JSON.stringify.
 *
 * Run with: deno test deno/tests/fixture_test.ts
 */

import { assertEquals, assertExists } from "https://deno.land/std@0.224.0/assert/mod.ts";
import { join } from "https://deno.land/std@0.224.0/path/mod.ts";

const FIXTURES_DIR = join(
  new URL(".", import.meta.url).pathname,
  "..",
  "fixtures",
);

/** Read and parse a fixture JSON file. */
function loadFixture<T = unknown>(name: string): T {
  const path = join(FIXTURES_DIR, `${name}.json`);
  const text = Deno.readTextFileSync(path);
  return JSON.parse(text) as T;
}

/** Assert that a value round-trips through JSON serialization. */
function assertRoundTrip(value: unknown, label: string): void {
  const serialized = JSON.stringify(value);
  const deserialized = JSON.parse(serialized);
  assertEquals(deserialized, value, `${label} failed round-trip`);
}

// ── 1. Role ──────────────────────────────────────────────────────────────────

Deno.test("Role: user variant", () => {
  const role = loadFixture<string>("role_user");
  assertEquals(role, "user");
  assertRoundTrip(role, "Role::User");
});

Deno.test("Role: assistant variant", () => {
  const role = loadFixture<string>("role_assistant");
  assertEquals(role, "assistant");
  assertRoundTrip(role, "Role::Assistant");
});

Deno.test("Role: system variant", () => {
  const role = loadFixture<string>("role_system");
  assertEquals(role, "system");
  assertRoundTrip(role, "Role::System");
});

Deno.test("Role: tool variant", () => {
  const role = loadFixture<string>("role_tool");
  assertEquals(role, "tool");
  assertRoundTrip(role, "Role::Tool");
});

// ── 2. Message ───────────────────────────────────────────────────────────────

interface Message {
  role: string;
  content: string | ContentBlock[];
  name?: string;
  metadata?: unknown;
}

interface ContentBlock {
  type: string;
  [key: string]: unknown;
}

Deno.test("Message: user message", () => {
  const msg = loadFixture<Message>("message_user");
  assertEquals(msg.role, "user");
  assertEquals(typeof msg.content, "string");
  assertEquals(msg.content, "Hello, how are you?");
  assertEquals(msg.name, undefined);
  assertEquals(msg.metadata, undefined);
  assertRoundTrip(msg, "Message(user)");
});

Deno.test("Message: assistant message", () => {
  const msg = loadFixture<Message>("message_assistant");
  assertEquals(msg.role, "assistant");
  assertEquals(typeof msg.content, "string");
  assertEquals(msg.content, "I'm doing well, thank you!");
  assertRoundTrip(msg, "Message(assistant)");
});

Deno.test("Message: tool result message", () => {
  const msg = loadFixture<Message>("message_tool_result");
  assertEquals(msg.role, "tool");
  assertEquals(Array.isArray(msg.content), true);
  const blocks = msg.content as ContentBlock[];
  assertEquals(blocks.length, 1);
  assertEquals(blocks[0].type, "tool_result");
  assertEquals(blocks[0].tool_use_id, "tool-call-001");
  assertEquals(blocks[0].content, "File contents: fn main() {}");
  assertRoundTrip(msg, "Message(tool_result)");
});

// ── 3. ContentBlock ──────────────────────────────────────────────────────────

Deno.test("ContentBlock: text", () => {
  const block = loadFixture<ContentBlock>("content_block_text");
  assertEquals(block.type, "text");
  assertEquals(block.text, "Here is the analysis result.");
  assertRoundTrip(block, "ContentBlock::Text");
});

Deno.test("ContentBlock: tool_use", () => {
  const block = loadFixture<ContentBlock>("content_block_tool_use");
  assertEquals(block.type, "tool_use");
  assertEquals(block.id, "tool-call-001");
  assertEquals(block.name, "read_file");
  assertEquals((block.input as Record<string, string>).path, "/src/main.rs");
  assertRoundTrip(block, "ContentBlock::ToolUse");
});

Deno.test("ContentBlock: tool_result", () => {
  const block = loadFixture<ContentBlock>("content_block_tool_result");
  assertEquals(block.type, "tool_result");
  assertEquals(block.tool_use_id, "tool-call-001");
  assertEquals(typeof block.content, "string");
  assertRoundTrip(block, "ContentBlock::ToolResult");
});

// ── 4. Tool ──────────────────────────────────────────────────────────────────

interface ToolDef {
  name: string;
  description: string;
  input_schema: {
    type: string;
    properties?: Record<string, unknown>;
    required?: string[];
  };
  requires_approval: boolean;
  defer_loading: boolean;
  allowed_callers?: string[];
  input_examples?: unknown[];
}

Deno.test("Tool: sample tool with schema", () => {
  const tool = loadFixture<ToolDef>("tool_sample");
  assertEquals(tool.name, "read_file");
  assertEquals(tool.description, "Read the contents of a file at the given path");
  assertEquals(tool.input_schema.type, "object");
  assertExists(tool.input_schema.properties);
  assertExists(tool.input_schema.properties!.path);
  assertEquals(tool.input_schema.required, ["path"]);
  assertEquals(tool.requires_approval, false);
  assertEquals(tool.defer_loading, false);
  assertRoundTrip(tool, "Tool");
});

// ── 5. ToolResult ────────────────────────────────────────────────────────────

interface ToolResult {
  tool_use_id: string;
  content: string;
  is_error: boolean;
}

Deno.test("ToolResult: success", () => {
  const result = loadFixture<ToolResult>("tool_result_success");
  assertEquals(result.tool_use_id, "tool-call-001");
  assertEquals(result.content, "Operation completed successfully");
  assertEquals(result.is_error, false);
  assertRoundTrip(result, "ToolResult(success)");
});

Deno.test("ToolResult: error", () => {
  const result = loadFixture<ToolResult>("tool_result_error");
  assertEquals(result.tool_use_id, "tool-call-002");
  assertEquals(result.content, "File not found: /nonexistent.txt");
  assertEquals(result.is_error, true);
  assertRoundTrip(result, "ToolResult(error)");
});

// ── 6. ChatOptions ───────────────────────────────────────────────────────────

interface ChatOptions {
  temperature?: number;
  max_tokens?: number;
  top_p?: number;
  stop?: string[];
  system?: string;
}

Deno.test("ChatOptions: default", () => {
  const opts = loadFixture<ChatOptions>("chat_options_default");
  assertEquals(opts.temperature, 0.7);
  assertEquals(opts.max_tokens, 4096);
  assertEquals(opts.top_p, undefined);
  assertEquals(opts.stop, undefined);
  assertEquals(opts.system, undefined);
  assertRoundTrip(opts, "ChatOptions(default)");
});

Deno.test("ChatOptions: custom with all fields", () => {
  const opts = loadFixture<ChatOptions>("chat_options_custom");
  assertEquals(opts.temperature, 0.0);
  assertEquals(opts.max_tokens, 100);
  assertEquals(opts.top_p, 0.9);
  assertEquals(opts.stop, ["\n", "END"]);
  assertEquals(opts.system, "You are a helpful assistant.");
  assertRoundTrip(opts, "ChatOptions(custom)");
});

// ── 7. TaskStatus ────────────────────────────────────────────────────────────

const TASK_STATUSES = [
  "pending",
  "inprogress",
  "completed",
  "failed",
  "blocked",
  "skipped",
] as const;

for (const status of TASK_STATUSES) {
  Deno.test(`TaskStatus: ${status}`, () => {
    const value = loadFixture<string>(`task_status_${status}`);
    assertEquals(value, status);
    assertRoundTrip(value, `TaskStatus::${status}`);
  });
}

