// ── 9. Task ──────────────────────────────────────────────────────────────────

interface TaskDef {
  id: string;
  description: string;
  status: string;
  plan_id?: string;
  parent_id?: string;
  children: string[];
  depends_on: string[];
  priority: string;
  assigned_to?: string;
  iterations: number;
  summary?: string;
  created_at: number;
  updated_at: number;
  started_at?: number;
  completed_at?: number;
}

Deno.test("Task: sample task", () => {
  const task = loadFixture<TaskDef>("task_sample");
  assertEquals(task.id, "task-001");
  assertEquals(task.description, "Implement user authentication module");
  assertEquals(task.status, "pending");
  assertEquals(task.plan_id, undefined);
  assertEquals(task.parent_id, undefined);
  assertEquals(task.children, []);
  assertEquals(task.depends_on, []);
  assertEquals(task.priority, "normal");
  assertEquals(task.assigned_to, undefined);
  assertEquals(task.iterations, 0);
  assertEquals(task.summary, undefined);
  assertEquals(typeof task.created_at, "number");
  assertEquals(typeof task.updated_at, "number");
  assertEquals(task.started_at, undefined);
  assertEquals(task.completed_at, undefined);
  assertRoundTrip(task, "Task");
});

