// ── 11. Usage ────────────────────────────────────────────────────────────────

interface UsageDef {
  prompt_tokens: number;
  completion_tokens: number;
  total_tokens: number;
}

Deno.test("Usage: sample", () => {
  const usage = loadFixture<UsageDef>("usage_sample");
  assertEquals(usage.prompt_tokens, 150);
  assertEquals(usage.completion_tokens, 50);
  assertEquals(usage.total_tokens, 200);
  assertEquals(usage.prompt_tokens + usage.completion_tokens, usage.total_tokens);
  assertRoundTrip(usage, "Usage");
});

// ── 12. SearchResult ─────────────────────────────────────────────────────────

interface SearchResultDef {
  file_path: string;
  root_path: string | null;
  content: string;
  score: number;
  vector_score: number;
  keyword_score: number | null;
  start_line: number;
  end_line: number;
  language: string;
  project: string | null;
  indexed_at: number;
}

Deno.test("SearchResult: sample", () => {
  const result = loadFixture<SearchResultDef>("search_result_sample");
  assertEquals(result.file_path, "src/main.rs");
  assertEquals(result.root_path, "/home/user/project");
  assertEquals(typeof result.content, "string");
  assertEquals(result.score, 0.95);
  assertEquals(result.vector_score, 0.92);
  assertEquals(result.keyword_score, 0.88);
  assertEquals(result.start_line, 1);
  assertEquals(result.end_line, 3);
  assertEquals(result.language, "rust");
  assertEquals(result.project, "my-project");
  assertEquals(typeof result.indexed_at, "number");
  assertRoundTrip(result, "SearchResult");
});

// ── 13. PermissionMode ───────────────────────────────────────────────────────

const PERMISSION_MODES: Array<[string, string]> = [
  ["read_only", "read-only"],
  ["auto", "auto"],
  ["full", "full"],
];

for (const [fileSuffix, expected] of PERMISSION_MODES) {
  Deno.test(`PermissionMode: ${expected}`, () => {
    const value = loadFixture<string>(`permission_mode_${fileSuffix}`);
    assertEquals(value, expected);
    assertRoundTrip(value, `PermissionMode::${expected}`);
  });
}
